import {
  ChangeDetectionStrategy,
  Component,
  forwardRef,
  InjectionToken,
  model,
  ViewEncapsulation,
} from '@angular/core';

/**
 * ChainOfThought — root container for a list of reasoning steps. Mirrors
 * React `ChainOfThought`.
 *
 * Owns the open/close state shared between `<chain-of-thought-header>` and
 * `<chain-of-thought-content>`. Two-way bindable `[(open)]` plus
 * uncontrolled mode.
 */
export interface ChainOfThoughtState {
  isOpen: () => boolean;
  setOpen(open: boolean): void;
  toggle(): void;
}

export const CHAIN_OF_THOUGHT = new InjectionToken<ChainOfThoughtState>(
  'ChainOfThoughtState',
);

@Component({
  selector: 'chain-of-thought',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'not-prose block max-w-prose space-y-4',
  },
  providers: [
    {
      provide: CHAIN_OF_THOUGHT,
      useExisting: forwardRef(() => ChainOfThought),
    },
  ],
})
export class ChainOfThought implements ChainOfThoughtState {
  readonly open = model<boolean>(false);

  readonly isOpen = () => this.open();

  setOpen(open: boolean): void {
    this.open.set(open);
  }

  toggle(): void {
    this.open.update((v) => !v);
  }
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  ViewEncapsulation,
} from '@angular/core';

import { CHAIN_OF_THOUGHT } from './chain-of-thought';

/**
 * ChainOfThoughtContent — collapsible body that holds the step list.
 *
 * Renders only when the chain is open. Mirrors React
 * `ChainOfThoughtContent`. Lightweight (no JS collapse animation — relies
 * on Tailwind's `animate-in/out` utilities + visibility toggle).
 */
@Component({
  selector: 'chain-of-thought-content',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    @if (open()) {
      <div
        class="mt-2 space-y-3 text-popover-foreground outline-none animate-in slide-in-from-top-2"
      >
        <ng-content />
      </div>
    }
  `,
})
export class ChainOfThoughtContent {
  private readonly state = inject(CHAIN_OF_THOUGHT);
  protected readonly open = computed(() => this.state.isOpen());
}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  input,
  ViewEncapsulation,
} from '@angular/core';
import { cn } from '@gremorie/ng-core';

export type ChainOfThoughtStepStatus = 'complete' | 'active' | 'pending';

/**
 * ChainOfThoughtStep — one row in the chain. Mirrors React
 * `ChainOfThoughtStep`.
 *
 * Status drives muted/foreground color treatment. Label + optional
 * description are inputs; deeper content (e.g. search results) can be
 * projected after them.
 */
@Component({
  selector: 'chain-of-thought-step',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div class="relative mt-0.5">
      <!-- dot icon -->
      <svg
        width="16"
        height="16"
        viewBox="0 0 24 24"
        fill="currentColor"
        aria-hidden="true"
      >
        <circle cx="12.1" cy="12.1" r="1" />
      </svg>
      <div class="-mx-px absolute top-7 bottom-0 left-1/2 w-px bg-border"></div>
    </div>
    <div class="flex-1 space-y-2 overflow-hidden">
      <div>{{ label() }}</div>
      @if (description()) {
        <div class="text-muted-foreground text-xs">{{ description() }}</div>
      }
      <ng-content />
    </div>
  `,
  host: {
    '[class]': 'hostClass()',
  },
})
export class ChainOfThoughtStep {
  readonly label = input.required<string>();
  readonly description = input<string>();
  readonly status = input<ChainOfThoughtStepStatus>('complete');

  protected readonly hostClass = computed(() => {
    const statusStyles: Record<ChainOfThoughtStepStatus, string> = {
      complete: 'text-muted-foreground',
      active: 'text-foreground',
      pending: 'text-muted-foreground/50',
    };
    return cn(
      'flex gap-2 text-sm animate-in fade-in-0 slide-in-from-top-2',
      statusStyles[this.status()],
    );
  });
}

import {
  ChangeDetectionStrategy,
  Component,
  ViewEncapsulation,
} from '@angular/core';
import { Badge } from '@gremorie/ng-display';

/**
 * ChainOfThoughtSearchResults — flex-wrap container for search-result chips.
 *
 * Mirrors React `ChainOfThoughtSearchResults`.
 */
@Component({
  selector: 'chain-of-thought-search-results',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `<ng-content />`,
  host: {
    class: 'flex flex-wrap items-center gap-2',
  },
})
export class ChainOfThoughtSearchResults {}

/**
 * ChainOfThoughtSearchResult — small badge for one search result. Mirrors
 * React `ChainOfThoughtSearchResult` (which renders a `Badge` variant).
 *
 * Dogfoods `gn-badge` (variant `secondary`) from `@gremorie/ng-display`
 * with a tighter corner radius and lighter weight to match the React
 * blueprint (which passes `gap-1 px-2 py-0.5 font-normal` to Badge).
 */
@Component({
  selector: 'chain-of-thought-search-result',
  standalone: true,
  imports: [Badge],
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <gn-badge variant="secondary" class="rounded-md font-normal">
      <ng-content />
    </gn-badge>
  `,
  host: {
    class: 'inline-flex',
  },
})
export class ChainOfThoughtSearchResult {}

import {
  ChangeDetectionStrategy,
  Component,
  input,
  ViewEncapsulation,
} from '@angular/core';

/**
 * ChainOfThoughtImage — bounded image preview with optional caption inside a
 * chain step. Mirrors React `ChainOfThoughtImage`.
 */
@Component({
  selector: 'chain-of-thought-image',
  standalone: true,
  encapsulation: ViewEncapsulation.None,
  changeDetection: ChangeDetectionStrategy.OnPush,
  template: `
    <div
      class="relative flex max-h-[22rem] items-center justify-center overflow-hidden rounded-lg bg-muted p-3"
    >
      <ng-content />
    </div>
    @if (caption(); as c) {
      <p class="text-muted-foreground text-xs">{{ c }}</p>
    }
  `,
  host: {
    class: 'mt-2 space-y-2 block',
  },
})
export class ChainOfThoughtImage {
  readonly caption = input<string>();
}

export { ChainOfThought, CHAIN_OF_THOUGHT } from './chain-of-thought';
export type { ChainOfThoughtState } from './chain-of-thought';
export { ChainOfThoughtHeader } from './chain-of-thought-header';
export { ChainOfThoughtContent } from './chain-of-thought-content';
export {
  ChainOfThoughtStep,
  type ChainOfThoughtStepStatus,
} from './chain-of-thought-step';
export {
  ChainOfThoughtSearchResults,
  ChainOfThoughtSearchResult,
} from './chain-of-thought-search';
export { ChainOfThoughtImage } from './chain-of-thought-image';
